def normalize_mark_list(
    mark_list: Iterable[Union[Mark, MarkDecorator]]
) -> Iterable[Mark]:
    """
    Normalize an iterable of Mark or MarkDecorator objects into a list of marks
    by retrieving the `mark` attribute on MarkDecorator instances.

    :param mark_list: marks to normalize
    :returns: A new list of the extracted Mark objects
    """

def get_unpacked_marks(obj: object) -> Iterable[Mark]:
    """Obtain the unpacked marks that are stored on an object."""
    if inspect.isclass(obj):
        # When obj is a class, iterate through its MRO to collect marks
        # from all base classes, not just the first one found via getattr.
        # This ensures that markers from multiple base classes are merged.
        seen = set()
        result = []
        for cls in obj.__mro__:
            mark_list = cls.__dict__.get("pytestmark", [])
            if not isinstance(mark_list, list):
                mark_list = [mark_list]
            for mark in normalize_mark_list(mark_list):
                if mark.name not in seen:
                    seen.add(mark.name)
                    result.append(mark)
        return result
    else:
        mark_list = getattr(obj, "pytestmark", [])
        if not isinstance(mark_list, list):
            mark_list = [mark_list]
        return normalize_mark_list(mark_list)


def normalize_mark_list(
    mark_list: Iterable[Union[Mark, MarkDecorator]]
) -> Iterable[Mark]:
    """
    Normalize an iterable of Mark or MarkDecorator objects into a list of marks
    by retrieving the `mark` attribute on MarkDecorator instances.

    :param mark_list: marks to normalize
    :returns: A new list of the extracted Mark objects
    """
    for mark in mark_list:
        mark_obj = getattr(mark, "mark", mark)
        if not isinstance(mark_obj, Mark):
            raise TypeError(f"got {repr(mark_obj)} instead of Mark")

