"""Test edge cases for MRO marker resolution."""
import pytest

# Test 1: Basic case - single inheritance
@pytest.mark.foo
class Base:
    pass

class TestSingle(Base):
    def test_markers(self, request):
        markers = list(request.node.iter_markers())
        marker_names = [m.name for m in markers]
        print(f"Test 1 - Single inheritance: {marker_names}")
        assert "foo" in marker_names

# Test 2: Multiple inheritance with different markers
@pytest.mark.foo
class Foo:
    pass

@pytest.mark.bar
class Bar:
    pass

class TestMultiple(Foo, Bar):
    def test_markers(self, request):
        markers = list(request.node.iter_markers())
        marker_names = [m.name for m in markers]
        print(f"Test 2 - Multiple inheritance: {marker_names}")
        assert "foo" in marker_names
        assert "bar" in marker_names
        # foo should come before bar (Foo is first in MRO)
        assert marker_names.index("foo") < marker_names.index("bar")

# Test 3: Multiple inheritance with same marker (deduplication)
@pytest.mark.foo
class Foo2:
    pass

@pytest.mark.foo  # Same marker name
class Bar2:
    pass

class TestDedup(Foo2, Bar2):
    def test_markers(self, request):
        markers = list(request.node.iter_markers())
        marker_names = [m.name for m in markers]
        print(f"Test 3 - Deduplication: {marker_names}")
        # Should only have one 'foo' marker
        assert marker_names.count("foo") == 1

