class GrandParent:
    pass

@pytest.mark.bar
class Parent(GrandParent):
    pass

class TestThreeLevel(Parent):
    def test_markers(self, request):
        markers = list(request.node.iter_markers())
        marker_names = [m.name for m in markers]
        print(f"Test 4 - Three-level: {marker_names}")
        assert "foo" in marker_names
